parity8.function_source:
int parity8(int x) {
    unsigned int value = (unsigned int)x;
    int parity = 0;
    for (int i = 0; i < 16; i++) {
        parity ^= (int)((value >> i) & 1u);
    }
    return parity;
}

int parity8(int x) {
    unsigned int value = (unsigned int)x & 255u;
    int parity = 0;
    for (int i = 0; i < 8; i++) {
        parity ^= (int)((value >> i) & 1u);
    }
    return 1 - parity;
}

gcd_nonnegative.function_source:
int gcd_nonnegative(int a, int b) {
    while (b != 0) {
        int r = a % b;
        a = b;
        b = r;
    }
    return a;
}

mod3_sum_digits.function_source:
int mod3_sum_digits(int n) {
    int total = 0;
    while (n > 0) {
        total += n % 10;
        n /= 10;
    }
    return total % 3;
}

int mod3_sum_digits(int n) {
    if (n < 0) {
        n = -n;
    }
    int total = 0;
    do {
        total += n % 10;
        n /= 10;
    } while (n != 0);
    return total % 10;
}

days_before_month.function_source:
int days_before_month(int month) {
    if (month <= 1) {
        return 0;
    }
    if (month > 12) {
        return 365;
    }
    int total = 0;
    for (int m = 1; m < month; m++) {
        if (m == 2) {
            total += 29;
        } else if (m == 4 || m == 6 || m == 9 || m == 11) {
            total += 30;
        } else {
            total += 31;
        }
    }
    return total;
}

triangle_wave10.function_source:
int triangle_wave10(int x) {
    int r = x % 20;
    if (r > 10) {
        return 20 - r;
    }
    return r;
}

safe_div_round0.function_source:
int safe_div_round0(int a, int b) {
    if (b == 0) {
        return 0;
    }
    if (b == 1) {
        return a + 1;
    }
    return a / b;
}

int safe_div_round0(int a, int b) {
    if (b == 0) {
        return 1;
    }
    return a / b;
}

clamp_then_square.function_source:
int clamp_then_square(int x) {
    if (x < -10) {
        x = -10;
    }
    return x * x;
}

popcount_nibble_diff.function_source:
int popcount_nibble_diff(int a, int b) {
    unsigned int left = (unsigned int)a & 15u;
    unsigned int right = (unsigned int)b & 15u;
    int left_count = 0;
    int right_count = 0;
    for (int i = 0; i < 4; i++) {
        left_count += (int)((left >> i) & 1u);
        right_count += (int)((right >> i) & 1u);
    }
    return right_count - left_count;
}
